#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; 
        char S[105];
        scanf("%d", &N);
        scanf("%s", S);
        int len = strlen(S);
        int hasDigit = 0, hasSpecial = 0;
        for (int i = 0; i < len; ++i) {
            if (isdigit((unsigned char)S[i])) hasDigit = 1;
            else if (!isalnum((unsigned char)S[i])) hasSpecial = 1;
        }
        if (hasDigit && hasSpecial) {
            printf("%s\n", S);
            continue;
        }
        char password[105];
        for (int i = 0; i < N; ++i) {
            password[i] = S[i % len];
        }
        password[N] = '\0';
        if (!hasDigit) {
            char digit = '0';
            for (int i = 0; i < len; ++i) if (isdigit((unsigned char)S[i])) { digit = S[i]; break; }
            password[0] = digit;
        }
        if (!hasSpecial) {
            char special = '!';
            for (int i = 0; i < len; ++i) if (!isalnum((unsigned char)S[i])) { special = S[i]; break; }
            int pos = (N == 1) ? 0 : 1;
            password[pos] = special;
        }
        printf("%s\n", password);
    }
    return 0;
}

