import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            int N = Integer.parseInt(br.readLine().trim());
            String S = br.readLine().trim();
            boolean hasDigit = false, hasSpecial = false;
            for (char c : S.toCharArray()) {
                if (Character.isDigit(c)) hasDigit = true;
                else if (!Character.isLetterOrDigit(c)) hasSpecial = true;
            }
            if (hasDigit && hasSpecial) {
                out.append(S).append('\n');
                continue;
            }
            StringBuilder pwd = new StringBuilder(N);
            for (int i = 0; i < N; ++i) pwd.append(S.charAt(i % S.length()));
            if (!hasDigit) {
                char digit = '0';
                for (char c : S.toCharArray()) if (Character.isDigit(c)) { digit = c; break; }
                pwd.setCharAt(0, digit);
            }
            if (!hasSpecial) {
                char special = '!';
                for (char c : S.toCharArray()) if (!Character.isLetterOrDigit(c)) { special = c; break; }
                int pos = (N == 1) ? 0 : 1;
                pwd.setCharAt(pos, special);
            }
            out.append(pwd).append('\n');
        }
        System.out.print(out.toString());
    }
}

