const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(), 10);
let output = [];
for (let tc = 0; tc < T; ++tc) {
  const N = parseInt(lines[idx++].trim(), 10);
  const S = lines[idx++].trim();
  let hasDigit = false, hasSpecial = false;
  for (const ch of S) {
    if (/[0-9]/.test(ch)) hasDigit = true;
    else if (!/[a-zA-Z0-9]/.test(ch)) hasSpecial = true;
  }
  if (hasDigit && hasSpecial) {
    output.push(S);
    continue;
  }
  const pwd = [];
  for (let i = 0; i < N; ++i) pwd.push(S[i % S.length]);
  if (!hasDigit) {
    const digit = S.split('').find(c => /[0-9]/.test(c)) || '0';
    pwd[0] = digit;
  }
  if (!hasSpecial) {
    const special = S.split('').find(c => !/[a-zA-Z0-9]/.test(c)) || '!';
    const pos = (N === 1) ? 0 : 1;
    pwd[pos] = special;
  }
  output.push(pwd.join(''));
}
